// 7-Segment Counter — 0 to 9, button on pin 2
// Common Cathode display
// Segments: a=3, b=4, c=5, d=6, e=7, f=8, g=9
// Button: pin 2 (INPUT_PULLUP)

const int SEG_A = 3;
const int SEG_B = 4;
const int SEG_C = 5;
const int SEG_D = 6;
const int SEG_E = 7;
const int SEG_F = 8;
const int SEG_G = 9;
const int BTN_PIN = 2;

int counter = 0;
bool lastBtnState = HIGH;

void showDigit(int n) {
  // Turn off all segments first
  digitalWrite(SEG_A, LOW);
  digitalWrite(SEG_B, LOW);
  digitalWrite(SEG_C, LOW);
  digitalWrite(SEG_D, LOW);
  digitalWrite(SEG_E, LOW);
  digitalWrite(SEG_F, LOW);
  digitalWrite(SEG_G, LOW);

  if (n == 0) {
    digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH); digitalWrite(SEG_D, HIGH);
    digitalWrite(SEG_E, HIGH); digitalWrite(SEG_F, HIGH);
  }
  else if (n == 1) {
    digitalWrite(SEG_B, HIGH); digitalWrite(SEG_C, HIGH);
  }
  else if (n == 2) {
    digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_D, HIGH); digitalWrite(SEG_E, HIGH);
    digitalWrite(SEG_G, HIGH);
  }
  else if (n == 3) {
    digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH); digitalWrite(SEG_D, HIGH);
    digitalWrite(SEG_G, HIGH);
  }
  else if (n == 4) {
    digitalWrite(SEG_B, HIGH); digitalWrite(SEG_C, HIGH);
    digitalWrite(SEG_F, HIGH); digitalWrite(SEG_G, HIGH);
  }
  else if (n == 5) {
    digitalWrite(SEG_A, HIGH); digitalWrite(SEG_C, HIGH);
    digitalWrite(SEG_D, HIGH); digitalWrite(SEG_F, HIGH);
    digitalWrite(SEG_G, HIGH);
  }
  else if (n == 6) {
    digitalWrite(SEG_A, HIGH); digitalWrite(SEG_C, HIGH);
    digitalWrite(SEG_D, HIGH); digitalWrite(SEG_E, HIGH);
    digitalWrite(SEG_F, HIGH); digitalWrite(SEG_G, HIGH);
  }
  else if (n == 7) {
    digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH);
  }
  else if (n == 8) {
    digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH); digitalWrite(SEG_D, HIGH);
    digitalWrite(SEG_E, HIGH); digitalWrite(SEG_F, HIGH);
    digitalWrite(SEG_G, HIGH);
  }
  else if (n == 9) {
    digitalWrite(SEG_A, HIGH); digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH); digitalWrite(SEG_D, HIGH);
    digitalWrite(SEG_F, HIGH); digitalWrite(SEG_G, HIGH);
  }
}

void setup() {
  pinMode(SEG_A, OUTPUT);
  pinMode(SEG_B, OUTPUT);
  pinMode(SEG_C, OUTPUT);
  pinMode(SEG_D, OUTPUT);
  pinMode(SEG_E, OUTPUT);
  pinMode(SEG_F, OUTPUT);
  pinMode(SEG_G, OUTPUT);
  pinMode(BTN_PIN, INPUT_PULLUP);
  showDigit(0);
}

void loop() {
  bool btnState = digitalRead(BTN_PIN);

  // Detect falling edge (press)
  if (btnState == LOW && lastBtnState == HIGH) {
    delay(30); // debounce
    if (digitalRead(BTN_PIN) == LOW) {
      counter = counter + 1;
      if (counter > 9) {
        counter = 0;
      }
      showDigit(counter);
    }
  }
  lastBtnState = btnState;
}

